import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import BikeCard from '../components/BikeCard';

const Home = () => {
  const [featuredBikes, setFeaturedBikes] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchFeaturedBikes();
  }, []);

  const fetchFeaturedBikes = async () => {
    try {
      const response = await fetch('http://localhost:5000/api/bikes?category=Sports');
      const result = await response.json();
      
      if (result.success) {
        setFeaturedBikes(result.data.slice(0, 3));
      }
    } catch (error) {
      console.error('Error fetching featured bikes:', error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div>
      {/* Hero Section */}
      <section className="hero">
        <div className="hero-content">
          <h1>Ride Your Adventure With Premium Bikes</h1>
          <p>Discover the perfect bike for your journey. From city commutes to mountain adventures, we have the right ride for you.</p>
          <div className="hero-buttons">
            <Link to="/bikes" className="btn btn-secondary">Browse Bikes</Link>
            <Link to="/contact" className="btn btn-outline">Contact Us</Link>
          </div>
        </div>
      </section>

      {/* Features Section */}
      <section className="section">
        <div className="section-title">
          <h2>Why Choose Us</h2>
          <p>We provide the best bike rental experience with quality service</p>
        </div>
        <div className="grid grid-3">
          <div className="card feature-card">
            <div className="feature-icon">🏍️</div>
            <h3>Premium Bikes</h3>
            <p>Well-maintained, latest models with regular servicing and quality checks.</p>
          </div>
          <div className="card feature-card">
            <div className="feature-icon">💰</div>
            <h3>Best Prices</h3>
            <p>Competitive pricing with no hidden charges. Complete transparency.</p>
          </div>
          <div className="card feature-card">
            <div className="feature-icon">🛡️</div>
            <h3>Full Insurance</h3>
            <p>Comprehensive insurance coverage for your peace of mind.</p>
          </div>
        </div>
      </section>

      {/* Featured Bikes Section */}
      <section className="section" style={{ background: '#f8f9fa' }}>
        <div className="section-title">
          <h2>Featured Bikes</h2>
          <p>Check out our most popular bikes</p>
        </div>
        
        {loading ? (
          <div className="loading">
            <div className="spinner"></div>
          </div>
        ) : (
          <div className="grid grid-3">
            {featuredBikes.map(bike => (
              <BikeCard key={bike.id} bike={bike} />
            ))}
          </div>
        )}

        <div style={{ textAlign: 'center', marginTop: '3rem' }}>
          <Link to="/bikes" className="btn btn-primary">View All Bikes</Link>
        </div>
      </section>

      {/* How It Works Section */}
      <section className="section">
        <div className="section-title">
          <h2>How It Works</h2>
          <p>Renting a bike has never been easier</p>
        </div>
        <div className="grid grid-4">
          <div className="card feature-card">
            <div className="feature-icon">1</div>
            <h3>Choose Bike</h3>
            <p>Select from our wide range of premium bikes</p>
          </div>
          <div className="card feature-card">
            <div className="feature-icon">2</div>
            <h3>Book Online</h3>
            <p>Fill the booking form with your details</p>
          </div>
          <div className="card feature-card">
            <div className="feature-icon">3</div>
            <h3>Pick Up</h3>
            <p>Collect your bike from selected location</p>
          </div>
          <div className="card feature-card">
            <div className="feature-icon">4</div>
            <h3>Enjoy Ride</h3>
            <p>Have a safe and enjoyable journey</p>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Home;
